mapper.select:
SELECT ROWNUM AS RNUM, R.RSV_IDX, R.MEET_GUBUN, TO_CHAR(R.RSV_DATE, 'YYYY-MM-DD') AS RSV_DATE, R.SRT_TIME, R.END_TIME, R.TITLE, TO_CHAR(R.REGI_DATE, 'YYYY-MM-DD') AS REGI_DATE, E.NAME AS INWRITER_NAME, R.ATTACH_FILE_SEQ, ( SELECT COUNT(*) FROM ATTACH_FILE AF WHERE AF.ATTACH_FILE_SEQ = R.ATTACH_FILE_SEQ ) AS FILE_COUNT FROM MEETROM_RSV R LEFT JOIN EMPLOYEE E ON E.EMPNO = R.INWRITER_ID WHERE 1 = 1
AND R.MEET_GUBUN = #{meetGubun}
AND R.RSV_DATE >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND R.RSV_DATE <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND R.AREA_CODE = #{areaCode}
ORDER BY R.RSV_IDX DESC
